// src/pages/PrintMovimentacoesAluno.jsx

import React, { useEffect, useState } from 'react'
import axios from 'axios'
import { useLocation, useNavigate } from 'react-router-dom'

export default function PrintMovimentacoesAluno() {
  const { state: filters = {} } = useLocation()
  const navigate = useNavigate()
  const [resumo, setResumo] = useState([])
  const [loading, setLoading] = useState(true)

  // Utilitário para formatar "YYYY-MM-DD" → "DD/MM/YYYY"
  function formatarData(isoDate) {
    if (!isoDate) return '-'
    const [yyyy, mm, dd] = isoDate.split('-')
    return `${dd}/${mm}/${yyyy}`
  }

  // 1) Busca dados do relatório
  useEffect(() => {
    async function fetchData() {
      try {
        setLoading(true)

        console.log('Filtros recebidos via state:', filters)

        // Buscar dados do relatório
        const params = {}
        if (filters.periodoId) params.periodoId = filters.periodoId
        if (filters.from) params.from = filters.from
        if (filters.to) params.to = filters.to

        console.log('Buscando relatório com params:', params)
        const res = await axios.get('/api/movimentacoes/relatorio', { params })
        console.log('Dados recebidos:', res.data)
        setResumo(res.data || [])
      } catch (err) {
        console.error('Erro ao buscar relatório:', err)
      } finally {
        setLoading(false)
      }
    }
    fetchData()
  }, [filters])

  // 2) Dispara impressão e volta para esterilização
  useEffect(() => {
    if (loading) return
    setTimeout(() => {
      window.print()
      // Voltar para a página de esterilização após impressão
      setTimeout(() => {
        navigate('/esterilizacao', { replace: true })
      }, 1000)
    }, 200)
  }, [loading, navigate])

  if (loading) {
    return (
      <div className="p-8">
        <p>Preparando impressão...</p>
      </div>
    )
  }

  // 3) Aplica os filtros do usuário
  const listaFiltrada = resumo.filter(item => {
    const term = filters.searchTerm?.toLowerCase() || ''
    const matchTxt = [
      item.alunoNome,
      item.periodoNome
    ].some(f => f?.toLowerCase().includes(term))

    return matchTxt
  })

  return (
    <div className="printable bg-white p-8">
      <h2 className="text-2xl font-bold mb-4">Relatório de Movimentações por Aluno</h2>
      <p className="text-gray-600 mb-4">Resumo de entradas, saídas e saldo de caixas por aluno</p>

      {/* Exibe filtros usados */}
      {(filters.searchTerm || filters.periodoId || filters.from || filters.to) && (
        <div className="mb-4 text-gray-700">
          <span className="font-semibold">Filtros aplicados:</span>
          <ul className="list-disc list-inside ml-4">
            {filters.searchTerm && <li>Busca: "{filters.searchTerm}"</li>}
            {filters.periodoId && <li>Período específico selecionado</li>}
            {filters.from && filters.to && (
              <li>Período: {formatarData(filters.from)} até {formatarData(filters.to)}</li>
            )}
            {filters.from && !filters.to && (
              <li>A partir de: {formatarData(filters.from)}</li>
            )}
            {!filters.from && filters.to && (
              <li>Até: {formatarData(filters.to)}</li>
            )}
          </ul>
        </div>
      )}

      <div className="overflow-x-auto">
        <table className="min-w-full bg-white divide-y divide-gray-200 rounded-lg shadow-sm">
          <thead className="bg-gray-100">
            <tr>
              <th className="px-4 py-2 text-left text-xs font-medium text-gray-600 uppercase">#</th>
              <th className="px-4 py-2 text-left text-xs font-medium text-gray-600 uppercase">Aluno</th>
              <th className="px-4 py-2 text-left text-xs font-medium text-gray-600 uppercase">Período</th>
              <th className="px-4 py-2 text-left text-xs font-medium text-gray-600 uppercase">Saldo de Caixas</th>
              <th className="px-4 py-2 text-left text-xs font-medium text-gray-600 uppercase">Teve Entrada</th>
              <th className="px-4 py-2 text-left text-xs font-medium text-gray-600 uppercase">Teve Saída</th>
            </tr>
          </thead>
          <tbody className="bg-white divide-y divide-gray-200">
            {listaFiltrada.map((item, index) => (
              <tr key={item.alunoId || index} className="hover:bg-gray-50">
                <td className="px-4 py-2 text-sm text-gray-900">{index + 1}</td>
                <td className="px-4 py-2 text-sm font-medium text-gray-900">
                  {item.alunoNome || '-'}
                </td>
                <td className="px-2 py-2 text-sm text-gray-700">
                  {item.periodoNome || '-'}
                </td>
                <td className="px-4 py-2 text-sm text-gray-700">
                  <span className={`font-semibold ${
                    item.saldoTotal > 0 ? 'text-green-600' : 
                    item.saldoTotal < 0 ? 'text-red-600' : 'text-gray-600'
                  }`}>
                    {item.saldoTotal || 0}
                  </span>
                </td>
                <td className="px-4 py-2 text-sm text-gray-700">
                  <span className={`inline-flex items-center px-2 py-1 rounded-full text-xs font-medium ${
                    item.teveEntrada 
                      ? 'bg-green-100 text-green-800' 
                      : 'bg-red-100 text-red-800'
                  }`}>
                    {item.teveEntrada ? 'Sim' : 'Não'}
                  </span>
                </td>
                <td className="px-4 py-2 text-sm text-gray-700">
                  <span className={`inline-flex items-center px-2 py-1 rounded-full text-xs font-medium ${
                    item.teveSaida 
                      ? 'bg-green-100 text-green-800' 
                      : 'bg-red-100 text-red-800'
                  }`}>
                    {item.teveSaida ? 'Sim' : 'Não'}
                  </span>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* Rodapé da impressão */}
      <div className="mt-8 pt-4 border-t text-sm text-gray-500">
        <p>Relatório gerado em: {new Date().toLocaleString('pt-BR')}</p>
        <p>Total de alunos: {listaFiltrada.length}</p>
        <p>Período do relatório: {filters.from && filters.to ? `${formatarData(filters.from)} até ${formatarData(filters.to)}` : 'Todos os períodos'}</p>
        <p>Filtros aplicados: {filters.searchTerm ? `Busca: "${filters.searchTerm}"` : 'Sem filtro de busca'}</p>
      </div>

      {/* Estilos específicos para impressão */}
      <style>{`
        @media print {
          .printable {
            margin: 0 !important;
            padding: 20px !important;
          }

          table {
            page-break-inside: auto !important;
          }

          tr {
            page-break-inside: avoid !important;
            page-break-after: auto !important;
          }

          thead {
            display: table-header-group !important;
          }

          tfoot {
            display: table-footer-group !important;
          }
        }
      `}</style>
    </div>
  )
}
